    async subscribePush() {
        try {
            if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
                toast.error('Push notifications not supported in this browser');
                return;
            }
            const registration = await navigator.serviceWorker.ready;
            const vapidKey = await api.getVapidPublicKey();
            const subscription = await registration.pushManager.subscribe({
                userVisibleOnly: true,
                applicationServerKey: vapidKey
            });
            await api.post('/push-subscriptions/subscribe', {
                subscription: subscription.toJSON(),
                userAgent: navigator.userAgent
            });
            toast.success('Push notifications enabled');
            await handlers.loadPushStatus();
        } catch (err) {
            toast.error('Failed to subscribe: ' + err.message);
        }
    },


    async unsubscribePush() {
        try {
            const registration = await navigator.serviceWorker.ready;
            const subscription = await registration.pushManager.getSubscription();
            if (subscription) {
                await api.delete('/push-subscriptions/subscribe', { endpoint: subscription.endpoint });
                await subscription.unsubscribe();
            }
            toast.success('Push notifications disabled');
            await handlers.loadPushStatus();
        } catch (err) {
            toast.error('Failed to unsubscribe');
        }
    },


    async testPushNotification() {
        try {
            const result = await api.post('/push-subscriptions/test');
            toast.success(result.message || 'Test notification sent');
        } catch (err) {
            toast.error('Failed to send test notification');
        }
    },


