    // Vault Buddy (Chatbot) Management
    // ========================================

    // Toggle Vault Buddy modal open/closed,


    uploadReceiptPhoto: async function(files) {
        if (!files || files.length === 0) return;

        store.setState({ receiptParsing: true, receiptUploadProgress: 0 });

        try {
            await api.ensureCSRFToken();

            for (let i = 0; i < files.length; i++) {
                const file = files[i];

                // Validate file type
                const validTypes = ['image/jpeg', 'image/png', 'image/webp', 'application/pdf'];
                if (!validTypes.includes(file.type)) {
                    toast.error(`${file.name}: Invalid file type. Use JPG, PNG, WebP, or PDF`);
                    continue;
                }

                // Validate file size (10MB limit)
                if (file.size > 10 * 1024 * 1024) {
                    toast.error(`${file.name}: File too large. Maximum 10MB`);
                    continue;
                }

                // Convert to base64
                const base64 = await new Promise((resolve, reject) => {
                    const reader = new FileReader();
                    reader.onload = () => resolve(reader.result.split(',')[1]);
                    reader.onerror = reject;
                    reader.readAsDataURL(file);
                });

                // Upload and parse
                const result = await api.post('/receipts/upload', {
                    filename: file.name,
                    mimeType: file.type,
                    imageBase64: base64
                });

                store.setState({
                    receiptUploadProgress: Math.round(((i + 1) / files.length) * 100)
                });

                if (result.receipt) {
                    toast.success(`Parsed: ${result.receipt.source_file || file.name}`);
                }
            }

            // Reload queue after all uploads
            await handlers.loadReceiptQueue();
            toast.success('Receipt parsing complete');
        } catch (error) {
            console.error('Upload error:', error);
            toast.error('Failed to upload receipt: ' + error.message);
        } finally {
            store.setState({ receiptParsing: false, receiptUploadProgress: null });
        }
    },

    // Handle receipt dropzone,


    connectGmail: async function() {
        try {
            store.setState({ emailConnecting: true });

            // Get authorization URL from backend
            const response = await api.get('/email/authorize/gmail');
            const authUrl = response?.authorizationUrl;

            if (!authUrl) {
                store.setState({ emailConnecting: false });
                toast.error('Gmail OAuth is not configured. Set GMAIL_CLIENT_ID and GMAIL_CLIENT_SECRET in Railway.');
                return;
            }

            // Open popup window for OAuth flow
            const width = 600;
            const height = 700;
            const left = window.screen.width / 2 - width / 2;
            const top = window.screen.height / 2 - height / 2;

            const popup = window.open(
                authUrl,
                'gmail_oauth_popup',
                `width=${width},height=${height},left=${left},top=${top},toolbar=no,menubar=no,location=no,status=no`
            );

            if (!popup) {
                toast.error('Popup blocked - please allow popups for Gmail connection');
                store.setState({ emailConnecting: false });
                return;
            }

            // Show loading toast
            toast.info('Connecting to Gmail...');

            // Listen for OAuth callback via postMessage
            const handleMessage = async (event) => {
                if (event.origin !== window.location.origin) return;
                if (event.data && event.data.type === 'email-oauth-success') {
                    window.removeEventListener('message', handleMessage);
                    store.setState({ emailConnecting: false });
                    toast.success(`${event.data.provider === 'outlook' ? 'Outlook' : 'Gmail'} connected: ${event.data.email}`);
                    await handlers.loadEmailAccounts();
                    await handlers.loadEmailProviders?.();

                    // Refresh receipt/integration surfaces if currently viewing them
                    if (store.state.currentPage === 'receipt-parser' || store.state.currentPage === 'connections') {
                        const pageContent = store.state.currentPage === 'connections'
                            ? pages.connections()
                            : pages.receiptParser();
                        const pageElement = document.querySelector('.page-content');
                        if (pageElement) {
                            pageElement.innerHTML = sanitizeHTML(pageContent);  // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
                        }
                    }
                } else if (event.data && event.data.type === 'email-oauth-error') {
                    window.removeEventListener('message', handleMessage);
                    store.setState({ emailConnecting: false });
                    toast.error(`Gmail connection failed: ${event.data.error}`);
                }
            };

            window.addEventListener('message', handleMessage);

            // Timeout after 5 minutes
            setTimeout(() => {
                window.removeEventListener('message', handleMessage);
                if (store.state.emailConnecting) {
                    store.setState({ emailConnecting: false });
                    toast.error('Gmail connection timed out');
                }
            }, 5 * 60 * 1000);

        } catch (error) {
            console.error('Gmail OAuth error:', error);
            store.setState({ emailConnecting: false });
            toast.error('Failed to initiate Gmail connection');
        }
    },

